-- Isolation levels (least to most strict)
-- READ UNCOMMITTED: can read dirty (uncommitted) data — almost never used
-- READ COMMITTED: only reads committed data (default in Postgres, Oracle)
--   ↳ anomaly: non-repeatable read (same row, different value on re-read)
-- REPEATABLE READ: same row returns same value within a transaction (default MySQL)
--   ↳ anomaly: phantom read (new rows appear in range query)
-- SERIALIZABLE: transactions appear fully serial — no anomalies, lowest throughput

-- Spring: set isolation per transaction
@Transactional(isolation = Isolation.REPEATABLE_READ)
public void transferFunds(long from, long to, BigDecimal amount) {
    Account sender = repo.findByIdForUpdate(from); // SELECT FOR UPDATE
    Account receiver = repo.findById(to);
    sender.debit(amount);
    receiver.credit(amount);
    repo.save(sender);
    repo.save(receiver);
} // commit — both debits and credits visible atomically

// N+1 problem — 1 + N queries
List<Order> orders = orderRepo.findAll(); // 1 query
for (Order order : orders) {
    order.getItems().size(); // triggers 1 query per order — N queries!
}

// Fix 1: JOIN FETCH in JPQL
@Query("SELECT o FROM Order o JOIN FETCH o.items WHERE o.customerId = :id")
List<Order> findWithItems(@Param("id") long customerId);
// Issues 1 SQL JOIN — returns all data in one round trip

// Fix 2: @EntityGraph — declarative fetch
@EntityGraph(attributePaths = {"items", "items.product"})
List<Order> findByCustomerId(long customerId);

// Fix 3: Batch fetching (Hibernate) — fetches items for N orders in batches
@OneToMany(fetch = FetchType.LAZY)
@BatchSize(size = 30) // fetches items for 30 orders per query
private List<Item> items;

// Detecting N+1 in tests
spring.jpa.show-sql=true
spring.jpa.properties.hibernate.generate_statistics=true
// Or: Hibernate Statistics bean → count queries per request

// LazyInitializationException scenario
@Transactional
public Order findOrder(long id) {
    return orderRepo.findById(id).orElseThrow();
} // transaction closes here — Session closes

// In controller (outside @Transactional):
Order order = service.findOrder(42);
order.getItems().size(); // LIE! Session already closed

// Fix 1: load within transaction (preferred)
@Transactional
public OrderDto findOrderWithItems(long id) {
    Order order = orderRepo.findById(id).orElseThrow();
    Hibernate.initialize(order.getItems()); // explicit init within session
    return OrderDto.from(order); // map to DTO — no lazy proxies escape
}

// Fix 2: disable OSIV (recommended for production)
# application.properties
spring.jpa.open-in-view=false
# Forces you to handle lazy loading properly
# Prevents accidental lazy loads during JSON serialization

// Best practice: map to DTOs inside @Transactional
// Never let JPA entities escape the service layer

// Optimistic locking — @Version field
@Entity
public class Product {
    @Id long id;
    int stock;
    @Version int version; // Hibernate manages this automatically
}

// Transaction 1 reads: version=5, stock=10
// Transaction 2 reads: version=5, stock=10
// Transaction 1 updates stock to 9 → version becomes 6, committed
// Transaction 2 tries to update → Hibernate detects version mismatch
//   → throws OptimisticLockException

// Retry on OptimisticLockException
@Retryable(value = OptimisticLockException.class, maxAttempts = 3)
@Transactional
public void decrementStock(long productId) {
    Product p = productRepo.findById(productId).orElseThrow();
    p.setStock(p.getStock() - 1);
    productRepo.save(p); // Hibernate auto-checks version
}

// Pessimistic locking — acquires DB row lock immediately
@Transactional
public void bookSeat(long seatId) {
    Seat seat = seatRepo.findById(seatId,
        LockModeType.PESSIMISTIC_WRITE).orElseThrow(); // SELECT FOR UPDATE
    if (!seat.isAvailable()) throw new SeatTakenException();
    seat.reserve();
} // row lock released on commit
